from flask import Flask, request, jsonify
import psycopg2
import os

app = Flask(__name__)

DB_HOST = os.getenv("DB_HOST", "localhost")
DB_PORT = os.getenv("DB_PORT", "5432")
DB_NAME = os.getenv("DB_NAME", "postgres")
DB_USER = os.getenv("DB_USER", "postgres")
DB_PASSWORD = os.getenv("DB_PASSWORD", "postgres")


def get_connection():
    return psycopg2.connect(
        host=DB_HOST,
        port=DB_PORT,
        dbname=DB_NAME,
        user=DB_USER,
        password=DB_PASSWORD,
    )


@app.route("/query", methods=["POST"])
def dynamic_query():
    data = request.get_json(force=True)

    table = data.get("table")
    columns = data.get("columns", ["*"])
    filters = data.get("filters", {})
    limit = data.get("limit")
    order_by = data.get("order_by")

    if not table:
        return jsonify({"error": "table is required"}), 400

    columns_sql = ", ".join(columns) if isinstance(columns, list) and columns else "*"
    query = f"SELECT {columns_sql} FROM {table}"
    params = []

    if filters and isinstance(filters, dict):
        where_clauses = []
        for key, value in filters.items():
            where_clauses.append(f"{key} = %s")
            params.append(value)
        query += " WHERE " + " AND ".join(where_clauses)

    if order_by:
        query += f" ORDER BY {order_by}"

    if limit is not None:
        query += f" LIMIT {int(limit)}"

    conn = None
    cur = None
    try:
        conn = get_connection()
        cur = conn.cursor()
        cur.execute(query, params)
        rows = cur.fetchall()
        colnames = [desc[0] for desc in cur.description]
        result = [dict(zip(colnames, row)) for row in rows]
        return jsonify({"query": query, "params": params, "results": result})
    except Exception as e:
        return jsonify({"error": str(e), "query": query, "params": params}), 500
    finally:
        if cur:
            cur.close()
        if conn:
            conn.close()


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000, debug=True)